class Solution {
    public int maxStability(int n, int[][] edges, int k) {
        Arrays.sort(edges, (a, b) -> a[2] - b[2]);
        int[] parent = new int[n];
        for (int i = 0; i < n; i++) {
            parent[i] = i;
        }
        int res = 0, cnt = 0;
        for (int[] edge : edges) {
            int u = edge[0], v = edge[1], s = edge[2], must = edge[3];
            if (must == 1) {
                if (union(parent, u, v)) {
                    res = Math.min(res, s);
                    cnt++;
                }
            } else {
                if (cnt < n - 1) {
                    if (union(parent, u, v)) {
                        res = Math.min(res, s);
                        cnt++;
                    }
                } else {
                    k--;
                    if (k >= 0) {
                        res = Math.min(res, s * 2);
                    } else {
                        break;
                    }
                }
            }
        }
        return cnt == n - 1 ? res : -1;
    }

    private boolean union(int[] parent, int u, int v) {
        int ru = find(parent, u);
        int rv = find(parent, v);
        if (ru != rv) {
            parent[ru] = rv;
            return true;
        }
        return false;
    }

    private int find(int[] parent, int u) {
        return parent[u] == u ? u : find(parent, parent[u]);
    }
}
